struct FileHandle {
    inner: Option<std::fs::File>,
}
impl FileHandle {
    fn new(path: &str) -> Self {
        FileHandle { inner: Some(std::fs::File::open(path).unwrap()) }
    }
    fn read_to_string(&mut self, buf: &mut String) -> std::io::Result<()> {
        match self.inner.take() {
            Some(file) => file.read_to_string(buf),
            None => Err(std::io::Error::new(std::io::ErrorKind::Other, "already closed")),
        }
    }
}
impl Drop for FileHandle {
    fn drop(&mut self) {
        if let Some(file) = self.inner.take() {
            drop(file);
        }
    }
}
```

```rust
use std::sync::{Arc, Mutex};
struct FileHandle {
    inner: Arc<Mutex<std::fs::File>>,
}
impl FileHandle {
    fn new(path: &str) -> Self {
        FileHandle { inner: Arc::new(Mutex::new(std::fs::File::open(path).unwrap())) }
    }
    fn read_to_string(&mut self, buf: &mut String) -> std::io::Result<()> {
        let mut file = self.inner.lock().unwrap();
        file.read_to_string(buf)
    }
}
impl Drop for FileHandle {
    fn drop(&mut self) {
        // The file will be closed when the last Arc<Mutex<_>> is dropped
    }
}
```

